// WF-1.1 Smart Waitlist - Slot Detection Logic
// Compares current calendar state against previous snapshot
// to detect newly opened slots from cancellations

try {
  const settings = $('Workflow Settings').first().json;

  // Get current calendar events
  const calendarData = $('Fetch Calendar Events').first().json;
  const currentEvents = (calendarData.items || []).map(event => ({
    id: event.id,
    summary: event.summary || 'No Title',
    start: event.start?.dateTime || event.start?.date,
    end: event.end?.dateTime || event.end?.date,
    status: event.status
  })).filter(e => e.status !== 'cancelled');

  // Get previous snapshot
  const previousSnapshot = $('Fetch Previous Snapshot').all().map(item => ({
    id: item.json.eventId,
    summary: item.json.summary,
    start: item.json.startTime,
    end: item.json.endTime
  }));

  // Find events that were in previous snapshot but NOT in current
  // These represent cancellations or rescheduled appointments
  const currentEventIds = new Set(currentEvents.map(e => e.id));
  const cancelledSlots = previousSnapshot.filter(prev => !currentEventIds.has(prev.id));

  // Also detect time blocks that are now free
  // Build a simple availability map for business hours (9 AM - 6 PM)
  const now = new Date();
  const lookAhead = new Date(now.getTime() + (settings.lookAheadHours * 60 * 60 * 1000));

  const openSlots = [];

  for (const cancelled of cancelledSlots) {
    const slotStart = new Date(cancelled.start);
    const slotEnd = new Date(cancelled.end);

    // Only include future slots
    if (slotStart > now) {
      openSlots.push({
        originalEventId: cancelled.id,
        originalSummary: cancelled.summary,
        slotDate: slotStart.toISOString().split('T')[0],
        slotStartTime: slotStart.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true }),
        slotEndTime: slotEnd.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true }),
        slotStartISO: slotStart.toISOString(),
        slotEndISO: slotEnd.toISOString(),
        slotDurationMinutes: Math.round((slotEnd - slotStart) / (1000 * 60)),
        detectedAt: now.toISOString()
      });
    }
  }

  // Return results
  if (openSlots.length === 0) {
    return [{ json: { hasOpenSlots: false, openSlotCount: 0, openSlots: [], message: 'No new cancellations detected' } }];
  }

  return [{ json: { hasOpenSlots: true, openSlotCount: openSlots.length, openSlots: openSlots, message: `${openSlots.length} open slot(s) detected from cancellations` } }];

} catch (error) {
  return [{ json: { hasOpenSlots: false, openSlotCount: 0, openSlots: [], error: true, errorMessage: error.message } }];
}

// Prepare current calendar events for snapshot storage
// This replaces the previous snapshot so next run can detect changes

try {
  const calendarData = $('Fetch Calendar Events').first().json;
  const events = (calendarData.items || []).filter(e => e.status !== 'cancelled');

  const snapshotRows = events.map(event => ({
    json: {
      eventId: event.id,
      summary: event.summary || 'No Title',
      startTime: event.start?.dateTime || event.start?.date,
      endTime: event.end?.dateTime || event.end?.date,
      updatedAt: new Date().toISOString()
    }
  }));

  if (snapshotRows.length === 0) {
    return [{ json: { message: 'No events to snapshot', count: 0 } }];
  }

  return snapshotRows;

} catch (error) {
  return [{ json: { error: true, errorMessage: error.message } }];
}

// Split open slots into individual items for processing

