const openSlots = data.openSlots || [];

return openSlots.map(slot => ({ json: slot }));

// WF-1.1 Smart Waitlist - Candidate Matching Algorithm
// Ranks waitlisted clients by priority, availability preference, and wait time
// HIPAA Note: No PHI is included in outgoing SMS messages

try {
  const settings = $('Workflow Settings').first().json;
  const slot = $('Split Open Slots').item.json;
  const waitlistRaw = $('Fetch Waitlist').all();

  // Filter to active waitlist entries only
  const activeWaitlist = waitlistRaw
    .map(item => item.json)
    .filter(entry => {
      const status = (entry.status || '').toLowerCase();
      return status === 'active' || status === 'waiting';
    });

  if (activeWaitlist.length === 0) {
    return [{ json: { hasCandidates: false, slotInfo: slot, message: 'No active waitlist entries found' } }];
  }

  // Parse slot date info
  const slotDate = new Date(slot.slotStartISO);
  const slotDay = slotDate.toLocaleDateString('en-US', { weekday: 'long' }).toLowerCase();
  const slotHour = slotDate.getHours();

  // Score each candidate
  const scoredCandidates = activeWaitlist.map(entry => {
    let score = 0;

    // Priority level scoring (high=30, medium=20, normal=10)
    const priority = (entry.priority || 'normal').toLowerCase();
    if (priority === 'high' || priority === 'urgent') score += 30;
    else if (priority === 'medium') score += 20;
    else score += 10;

    // Day preference matching
    const preferredDays = (entry.preferredDays || '').toLowerCase();
    if (preferredDays === 'any' || preferredDays === '') score += 15;
    else if (preferredDays.includes(slotDay)) score += 15;
    else score -= 5;

    // Time preference matching
    const preferredTime = (entry.preferredTime || '').toLowerCase();
    if (preferredTime === 'any' || preferredTime === '') score += 10;
    else if (preferredTime === 'morning' && slotHour < 12) score += 10;
    else if (preferredTime === 'afternoon' && slotHour >= 12 && slotHour < 17) score += 10;
    else if (preferredTime === 'evening' && slotHour >= 17) score += 10;
    else score -= 5;

    // Wait time bonus (longer wait = higher priority)
    const addedDate = entry.dateAdded ? new Date(entry.dateAdded) : new Date();
    const daysWaiting = Math.floor((new Date() - addedDate) / (1000 * 60 * 60 * 24));
    score += Math.min(daysWaiting * 2, 20); // Cap at 20 bonus points

    // Penalize if recently contacted (within last 24 hours)
    if (entry.lastContacted) {
      const lastContact = new Date(entry.lastContacted);
      const hoursSinceContact = (new Date() - lastContact) / (1000 * 60 * 60);
      if (hoursSinceContact < 24) score -= 50; // Heavy penalty to avoid spamming
    }

    return {
      ...entry,
      matchScore: score,
      daysWaiting: daysWaiting
    };
  });

  // Sort by score descending and take top candidates
  const maxCandidates = settings.maxCandidatesPerSlot || 3;
  const topCandidates = scoredCandidates
    .filter(c => c.matchScore > 0)
    .sort((a, b) => b.matchScore - a.matchScore)
    .slice(0, maxCandidates);

  if (topCandidates.length === 0) {
    return [{ json: { hasCandidates: false, slotInfo: slot, message: 'No suitable candidates for this slot' } }];
  }

  // Return top candidate for immediate contact, plus alternates
  return [{
    json: {
      hasCandidates: true,
      slotInfo: slot,
      primaryCandidate: topCandidates[0],
      alternateCandidates: topCandidates.slice(1),
      totalCandidatesScored: scoredCandidates.length,
      message: `Found ${topCandidates.length} candidate(s) for ${slot.slotDate} at ${slot.slotStartTime}`
    }
  }];

} catch (error) {
  return [{ json: { hasCandidates: false, error: true, errorMessage: error.message } }];
}
